export const checkId = 'database-config';
export const name = 'Database Configuration';
export const appliesTo = ['deployable', 'server', 'framework'];

const DB_DEPS = [
  'mongoose', 'sequelize', 'prisma', '@prisma/client', 'typeorm', 'knex',
  'pg', 'mysql2', 'mongodb', 'redis', 'ioredis', '@upstash/redis',
  'drizzle-orm', 'drizzle-kit', 'kysely', '@libsql/client', 'better-sqlite3',
  'postgres', 'sql.js', 'turso', '@planetscale/database', '@vercel/postgres',
  '@vercel/kv', 'tedious', 'oracledb', 'sqlite3', 'node-sqlite'
];

const GOOD_PATTERNS = [
  /process\.env\.(DATABASE_URL|DATABASE_HOST|DATABASE_NAME|DATABASE_PORT|DATABASE_USER|DATABASE_PASSWORD|DATABASE_USERNAME)/i,
  /process\.env\.(DB_HOST|DB_NAME|DB_PORT|DB_USER|DB_PASS|DB_PASSWORD|DB_USERNAME|DB_URL|DB_CONNECTION_STRING)/i,
  /process\.env\.(MONGO|MONGODB)_/i,
  /process\.env\.(REDIS|REDIS_URL|REDIS_HOST|REDIS_PORT)/i,
  /process\.env\.(PG_|POSTGRES_|POSTGRESQL_)/i,
  /process\.env\.(MYSQL_|MYSQL2_)/i,
  /process\.env\.[A-Z_]*DATABASE[A-Z_]*/i,
  /process\.env\.[A-Z_]*DB_[A-Z_]+/i,
  /env\s*\(\s*["'][^"']*DATABASE[^"']*["']\s*\)/i,
  /env\s*\(\s*["'][^"']*DB_[^"']*["']\s*\)/i,
  /env\s*\(\s*["'][^"']*(MONGO|REDIS|POSTGRES|POSTGRESQL|MYSQL|SQLITE|TURSO|LIBSQL|PLANETSCALE|NEON|SUPABASE|DRIZZLE)[^"']*["']\s*\)/i,
  /getConfigFromEnv\s*\(\s*['"]DB_/i,
  /getConfigFromEnv\s*\(\s*['"]DATABASE/i,
  /\$\{(DATABASE_URL|DB_HOST|DB_NAME|DB_PORT|DATABASE_[A-Z_]+)\}/i,
  /\$\{(MONGO|MONGODB|REDIS|POSTGRES|POSTGRESQL|MYSQL|SQLITE|TURSO|LIBSQL|PLANETSCALE|NEON|SUPABASE|DRIZZLE)[A-Z_]*\}/i,
  /^(DATABASE_URL|DATABASE_HOST|DATABASE_NAME|DATABASE_PORT|DATABASE_USER|DATABASE_PASSWORD)=/im,
  /^(DB_HOST|DB_NAME|DB_PORT|DB_USER|DB_PASS|DB_PASSWORD|DB_URL)=/im,
  /^(MONGO|MONGODB)_/im,
  /^(PG_|POSTGRES_|POSTGRESQL_)/im,
  /^(REDIS_URL|REDIS_HOST|REDIS_PORT)=/im,
  /^(SQLITE|TURSO|LIBSQL|PLANETSCALE|NEON|SUPABASE|DRIZZLE)_/im,
];

const BAD_PATTERNS = [
  /(mongodb|mongodb\+srv|postgres|postgresql|mysql|redis):\/\/[^:]+:[^@\s]+@\S+/i,
  /mysql:\/\/\w+:\w+@\w+/i,
  /postgres(ql)?:\/\/\w+:[^@\s]+@\w+/i,
];

const STRONG_INDICATOR_PATTERNS = [
  /(^|[\/])(db|database|model)s?[\/]/i,
  /(^|[\/])prisma[\/]/i,
  /(^|[\/])drizzle[\/]/i,
  /(^|[\/])(config|configs)[\/](db|database|mongo|postgres|mysql|redis|sqlite|drizzle)/i,
  /(^|[\/])([^\/]*\.)?(db|database|mongo|postgres|mysql|redis|sqlite|drizzle)([^\/]*)?\.(js|ts|mjs|cjs)$/i,
];

const WEAK_INDICATOR_PATTERNS = [
  /\.env/i,
  /(docker-compose|compose\.)/i,
  /(^|[\/])connection\.(js|ts|mjs|cjs)$/i,
];

const SCAN_EXTENSIONS = /\.(js|ts|mjs|cjs|prisma|yml|yaml)$/i;
const ENV_EXTENSIONS = /\.env/;

function isDbDriverLibrary(packageJson) {
  if (!packageJson?.name) return false;
  const name = packageJson.name;
  if (DB_DEPS.includes(name)) return true;
  if (name.startsWith('@')) {
    const base = name.split('/')[1];
    if (base && DB_DEPS.includes(base)) return true;
  }
  return false;
}

export async function check(context) {
  const { tree, files, packageJson } = context;

  try {
    if (isDbDriverLibrary(packageJson)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: `DB driver library (${packageJson.name}) — not applicable`, findings: [] };
    }

    // 1. Discover DB deps across the monorepo
    const pkgPaths = tree.filter(p => p.endsWith('package.json') && !/node_modules|\.git/.test(p)).slice(0, 25);
    let hasDbDep = false;

    for (const p of pkgPaths) {
      const content = await files.get(p);
      if (!content) continue;
      let pkg;
      try {
        pkg = JSON.parse(content);
      } catch {
        continue;
      }
      const deps = { ...pkg.dependencies, ...pkg.devDependencies };
      if (DB_DEPS.some(d => deps[d])) {
        hasDbDep = true;
        break;
      }
    }

    if (!hasDbDep && packageJson) {
      const rootDeps = { ...packageJson.dependencies, ...packageJson.devDependencies };
      if (DB_DEPS.some(d => rootDeps[d])) {
        hasDbDep = true;
      }
    }

    // 2. Strong path-based indicators
    const strongMatches = tree.filter(p => {
      if (!SCAN_EXTENSIONS.test(p)) return false;
      if (/node_modules|\.git/.test(p)) return false;
      if (/(test|spec|example)s?[\/]/i.test(p)) return false;
      return STRONG_INDICATOR_PATTERNS.some(pat => pat.test(p));
    });

    if (!hasDbDep && strongMatches.length === 0) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'No database dependency or DB-related files found', findings: [] };
    }

    // 3. Build prioritized scan list with category caps so high-signal files aren't crowded out
    const MAX_ENV = 10;
    const MAX_CONFIG = 20;
    const MAX_DOCKER = 5;
    const MAX_OTHER = 15;
    const MAX_TOTAL = 50;

    const envFiles = tree.filter(p => {
      if (!ENV_EXTENSIONS.test(p)) return false;
      if (/node_modules|\.git/.test(p)) return false;
      if (/\.(test|spec|fixture|mock)\.env$/i.test(p)) return false;
      return true;
    }).slice(0, MAX_ENV);

    const configFiles = tree.filter(p => {
      if (!SCAN_EXTENSIONS.test(p)) return false;
      if (/node_modules|\.git/.test(p)) return false;
      if (/(test|spec|example)s?[\/]/i.test(p)) return false;
      return STRONG_INDICATOR_PATTERNS.some(pat => pat.test(p));
    }).slice(0, MAX_CONFIG);

    const dockerFiles = tree.filter(p => {
      if (!/\.(yml|yaml)$/.test(p)) return false;
      if (/node_modules|\.git/.test(p)) return false;
      return /docker-compose|compose\./i.test(p);
    }).slice(0, MAX_DOCKER);

    const scannedSet = new Set([...envFiles, ...configFiles, ...dockerFiles]);

    const otherFiles = tree.filter(p => {
      if (scannedSet.has(p)) return false;
      if (!SCAN_EXTENSIONS.test(p)) return false;
      if (/node_modules|\.git/.test(p)) return false;
      if (/(test|spec|example)s?[\/]/i.test(p)) return false;
      return [...STRONG_INDICATOR_PATTERNS, ...WEAK_INDICATOR_PATTERNS].some(pat => pat.test(p));
    }).slice(0, MAX_OTHER);

    const sourceFiles = Array.from(new Set([...envFiles, ...configFiles, ...dockerFiles, ...otherFiles])).slice(0, MAX_TOTAL);

    // 4. Scan file contents
    let foundGood = false;
    let foundBad = false;
    const findings = [];

    for (const filePath of sourceFiles) {
      const content = await files.get(filePath);
      if (!content) continue;

      for (const pattern of GOOD_PATTERNS) {
        if (pattern.test(content)) {
          foundGood = true;
          const lines = content.split('\n');
          for (let i = 0; i < lines.length; i++) {
            if (pattern.test(lines[i])) {
              findings.push({ file: filePath, line: i + 1, issue: 'DB config uses environment variables' });
              break;
            }
          }
        }
      }

      const isEnvTemplate = /(^|[\/])\.env\./i.test(filePath);
      const isDockerCompose = /docker-compose|compose\./i.test(filePath);

      if (!isEnvTemplate && !isDockerCompose) {
        for (const pattern of BAD_PATTERNS) {
          const re = new RegExp(pattern.source, 'gmi');
          let match;
          let count = 0;
          while ((match = re.exec(content)) !== null && count < 3) {
            count++;
            foundBad = true;
            const snippet = match[0].substring(0, 60);
            const lines = content.split('\n');
            for (let i = 0; i < lines.length; i++) {
              if (lines[i].includes(snippet)) {
                findings.push({ file: filePath, line: i + 1, issue: 'Hardcoded DB connection string with credentials' });
                break;
              }
            }
          }
        }
      }
    }

    if (foundBad) {
      return { checkId, status: 'fail', confidence: 'high', message: 'Hardcoded DB credentials detected', findings };
    }
    if (foundGood) {
      return { checkId, status: 'pass', confidence: 'high', message: 'DB configured with environment variables', findings };
    }
    if (hasDbDep) {
      return { checkId, status: 'check-it', confidence: 'medium', message: 'DB dependency found but could not verify env-based configuration in scanned files', findings: [] };
    }
    return { checkId, status: 'check-it', confidence: 'low', message: 'Could not determine DB configuration', findings: [] };
  } catch (err) {
    console.error(`[database-config] error:`, err);
    return { checkId, status: 'check-it', confidence: 'low', message: `Error: ${err.message}`, findings: [] };
  }
}
